package com.cognizant.payment.service;import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;import io.github.resilience4j.retry.annotation.Retry;import org.slf4j.*;import org.springframework.stereotype.Service;import org.springframework.web.client.RestClient;import java.util.Map;@Service public class PaymentService{private static final Logger log=LoggerFactory.getLogger(PaymentService.class);private final RestClient client=RestClient.create("http://localhost:8402");@CircuitBreaker(name="paymentApi",fallbackMethod="fallback")@Retry(name="paymentApi") public Map pay(long delay){return client.get().uri("/third-party/pay?delay="+delay).retrieve().body(Map.class);}public Map fallback(long delay,Throwable t){log.warn("Fallback executed: {}",t.toString());return Map.of("status","PENDING","message","Fallback response: provider temporarily unavailable");}}